+import React, { useEffect, useState } from 'react';
+import PropTypes from 'prop-types';
+
+// Pixel-art styled bubble with tail pointing to character
+// type: 'speech' or 'thought'
+// text: string to show
+// onHide: callback when bubble auto-hides
+const CharacterBubble = ({ type, text, onHide }) => {
+  const [visible, setVisible] = useState(true);
+
+  useEffect(() => {
+    // Auto-hide after 3-5 seconds randomly
+    const timeout = 3000 + Math.floor(Math.random() * 2000);
+    const timer = setTimeout(() => {
+      setVisible(false);
+      if (onHide) onHide();
+    }, timeout);
+    return () => clearTimeout(timer);
+  }, [onHide]);
+
+  if (!visible) return null;
+
+  // Truncate text to ~30 chars
+  const truncated = text.length > 30 ? text.slice(0, 27) + '...' : text;
+
+  // Pixel art bubble styles
+  const bubbleStyle = {
+    position: 'absolute',
+    maxWidth: 160,
+    padding: '6px 10px',
+    backgroundColor: type === 'speech' ? '#fff' : '#eef3ff',
+    border: '2px solid #000',
+    borderRadius: 6,
+    fontFamily: '"Press Start 2P", cursive, monospace',
+    fontSize: 10,
+    color: '#000',
+    userSelect: 'none',
+    pointerEvents: 'none',
+    boxShadow: '2px 2px 0 #000',
+    whiteSpace: 'nowrap',
+    lineHeight: 1.2,
+    zIndex: 10,
+  };
+
+  // Tail styles using CSS triangles pixel-art style
+  const tailStyle = {
+    position: 'absolute',
+    width: 0,
+    height: 0,
+    borderStyle: 'solid',
+    borderWidth: '8px 6px 0 6px',
+    borderColor: type === 'speech' ? '#fff transparent transparent transparent' : '#eef3ff transparent transparent transparent',
+    left: '50%',
+    bottom: -8,
+    transform: 'translateX(-50%)',
+    boxShadow: '2px 2px 0 #000',
+  };
+
+  // Tail border (black outline)
+  const tailBorderStyle = {
+    position: 'absolute',
+    width: 0,
+    height: 0,
+    borderStyle: 'solid',
+    borderWidth: '10px 8px 0 8px',
+    borderColor: '#000 transparent transparent transparent',
+    left: '50%',
+    bottom: -10,
+    transform: 'translateX(-50%)',
+    zIndex: 9,
+  };
+
+  return (
+    <div style={bubbleStyle}>
+      {truncated}
+      <div style={tailBorderStyle} />
+      <div style={tailStyle} />
+    </div>
+  );
+};
+
+CharacterBubble.propTypes = {
+  type: PropTypes.oneOf(['speech', 'thought']).isRequired,
+  text: PropTypes.string.isRequired,
+  onHide: PropTypes.func,
+};
+
+export default CharacterBubble;
